export const getAllFighters = async () => {
    try {
        const res = await fetch('/fighters/', {
            headers: {
                'Accept': 'application/json'
            }
        });
        if (!res.ok) {
            throw new Error(`Failed to fetch fighters: ${res.status}`);
        }
        return await res.json();
    } catch (error) {
        console.error('API Error:', error);
        throw error;
    }
};
